package com.nutrisense.entity;
import jakarta.persistence.*; import lombok.*; import java.math.*; import java.time.*;
@Getter @Setter @Builder @NoArgsConstructor @AllArgsConstructor @Entity @Table(name="workout_logs") public class WorkoutLog { @Id @GeneratedValue(strategy=GenerationType.IDENTITY) private Long id; @ManyToOne(fetch=FetchType.LAZY,optional=false) @JoinColumn(name="user_id",nullable=false) private User user; @ManyToOne(fetch=FetchType.LAZY,optional=false) @JoinColumn(name="workout_type_id",nullable=false) private WorkoutType workoutType; @Column(name="workout_date") private LocalDate workoutDate; @Column(name="duration_minutes") private Integer durationMinutes; @Column(name="calories_burned",precision=8,scale=2) private BigDecimal caloriesBurned; @Lob @Column(columnDefinition="TEXT") private String notes; @Column(name="created_at",insertable=false,updatable=false) private Instant createdAt; }
